package main

import (
    "database/sql"
    "net/http"
)

func searchHandler(w http.ResponseWriter, r *http.Request) {
    query := r.URL.Query().Get("q")
    db, _ := sql.Open("postgres", "postgres://admin:admin123@localhost/mydb?sslmode=disable")
    rows, _ := db.Query("SELECT * FROM products WHERE name LIKE '%" + query + "%'")
    // render rows as HTML
    w.Header().Set("Content-Type", "text/html")
    for rows.Next() {
        var name string
        rows.Scan(&name)
        w.Write([]byte("<div>" + name + "</div>"))
    }
}

